//Store date
  function storeCurrentDate() {
    const today = new Date().toLocaleDateString("en-CA", { 
      timeZone: timezone, 
      year: "numeric", 
      month: "2-digit", 
      day: "2-digit" 
    });
  gwc.userdata.trax.currentdate = today
  }
//Check if new day
function isNewDay() {
  const today = new Date().toLocaleDateString("en-CA", { 
    timeZone: timezone, 
    year: "numeric", 
    month: "2-digit", 
    day: "2-digit" 
  });

return gwc.userdata.trax.currentdate !== today;
}

//Easier coin adding
function addCoin(type, amount) {
  if(trax.coinloot[type] != null){
    trax.coinloot[type] += amount;
  }
}

//Convert number words to digits
  function textToNumber(text) {
    text = text.toLowerCase().trim();
    if (text === "a" || text === "the") return 1;

    const ones = {
      zero:0, one:1, two:2, three:3, four:4,
      five:5, six:6, seven:7, eight:8, nine:9,
      ten:10, eleven:11, twelve:12, thirteen:13,
      fourteen:14, fifteen:15, sixteen:16,
      seventeen:17, eighteen:18, nineteen:19
    };

    const tens = {
      twenty:20, thirty:30, forty:40,
      fifty:50, sixty:60, seventy:70,
      eighty:80, ninety:90
    };

    let total = 0;
    let words = text.split(/\s+/);
    for (let w of words) {
      if (ones[w] !== undefined) total += ones[w];
      else if (tens[w] !== undefined) total += tens[w];
    }
    return total;
  }

