}

// Chop decimals
function toWhole(num) {
  return Math.trunc(num);
}

// Make bar 
  function makeBar(percent, length = 20) {
    percent = Math.max(0, Math.min(100, percent)); // clamp

    let filled = Math.round((percent / 100) * length);
    let empty = length - filled;

    let bar = "█".repeat(filled) + "-".repeat(empty);

    return `[${bar}] ${percent}%`;
  }

// Separator
function sep(color = c.sep[1]) {
    let sepp = `<span style="
      display:block;
      font-size:10px;
      line-height:8px;
      color:${color};
      letter-spacing:0px;
    ">     ─────────────────────────────────────────────────</span>`;
    gwc.output.append("SEPARATOR");gwc.output.replace("SEPARATOR",sepp)
  }

// Add commas to numbers
 function fn(num) {
